162	// fixedScanner implements workerstatus.Scanner over a static list. It is
163	// only referenced from tests but lives here so production code does not
164	// depend on test-only types.
165	type fixedScanner struct {
166		workers []workerstatus.LiveWorker
167	}
168	
169	func (s fixedScanner) Scan(_ context.Context) ([]workerstatus.LiveWorker, error) {
170		return s.workers, nil
171	}
